(function(){
  function crc32(buf){
    const table=new Uint32Array(256);
    for(let i=0;i<256;i++){
      let c=i;
      for(let k=0;k<8;k++){
        c=(c&1)?0xEDB88320^(c>>>1):(c>>>1);
      }
      table[i]=c>>>0;
    }
    let crc=0xFFFFFFFF;
    for(let i=0;i<buf.length;i++){
      crc=(crc>>>8)^table[(crc^buf[i])&0xFF];
    }
    return (crc^0xFFFFFFFF)>>>0;
  }

  function textBytes(str){
    return new TextEncoder().encode(str);
  }

  function concat(arrays){
    let total=0;
    arrays.forEach(a=>total+=a.length);
    const out=new Uint8Array(total);
    let pos=0;
    arrays.forEach(a=>{
      out.set(a,pos);
      pos+=a.length;
    });
    return out;
  }

  function write32(v){
    return new Uint8Array([
      v&255,
      (v>>8)&255,
      (v>>16)&255,
      (v>>24)&255
    ]);
  }

  function write16(v){
    return new Uint8Array([
      v&255,
      (v>>8)&255
    ]);
  }

  function zipSync(files){

    const localFiles=[];
    const central=[];
    let offset=0;

    Object.keys(files).forEach(name=>{

      const data=files[name];
      const filename=textBytes(name);
      const crc=crc32(data);

      const localHeader=concat([
        new Uint8Array([80,75,3,4]),
        write16(20),
        write16(0),
        write16(0),
        write16(0),
        write16(0),
        write32(crc),
        write32(data.length),
        write32(data.length),
        write16(filename.length),
        write16(0),
        filename,
        data
      ]);

      localFiles.push(localHeader);

      const centralHeader=concat([
        new Uint8Array([80,75,1,2]),
        write16(20),
        write16(20),
        write16(0),
        write16(0),
        write16(0),
        write16(0),
        write32(crc),
        write32(data.length),
        write32(data.length),
        write16(filename.length),
        write16(0),
        write16(0),
        write16(0),
        write16(0),
        write32(0),
        write32(offset),
        filename
      ]);

      central.push(centralHeader);

      offset+=localHeader.length;

    });

    const centralDir=concat(central);

    const end=concat([
      new Uint8Array([80,75,5,6]),
      write16(0),
      write16(0),
      write16(central.length),
      write16(central.length),
      write32(centralDir.length),
      write32(offset),
      write16(0)
    ]);

    return concat([
      ...localFiles,
      centralDir,
      end
    ]);
  }

  window.fflate={
    zipSync
  };

})();